import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import "./TacticalHexBadge.css";

function TacticalHexBadge({
  label = "NODE A",
  status = "STABLE",
  variant = "info",
  details = "System operating within normal parameters.",
}) {
  const [open, setOpen] = useState(false);

  return (
    <div className="hex-wrapper">
      <motion.div
        className={`hex-badge ${variant} ${
          variant === "critical" ? "glitch" : ""
        }`}
        onClick={() => setOpen(!open)}
        whileTap={{ scale: 0.95 }}
        transition={{ type: "spring", stiffness: 300, damping: 20 }}
      >
        <div className="inner-border" />
        <div className="corner-rotor" />
        <div className="scan-line" />

        <div className="hex-content">
          <span className="hex-label">{label}</span>
          <span className="hex-status">{status}</span>
        </div>
      </motion.div>

      <AnimatePresence>
        {open && (
          <motion.div
            className="hex-details"
            initial={{ opacity: 0, scale: 0.95, y: -5 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.95, y: -5 }}
            transition={{ type: "spring", stiffness: 260, damping: 20 }}
          >
            {details}
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

export default TacticalHexBadge;

.hex-wrapper {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 14px;
}

/* Proper Hex Ratio */
.hex-badge {
  width: 180px;
  height: 104px;
  position: relative;
  cursor: pointer;

  clip-path: polygon(
    25% 0%,
    75% 0%,
    100% 50%,
    75% 100%,
    25% 100%,
    0% 50%
  );

  background: linear-gradient(
    145deg,
    rgba(20, 30, 40, 0.95),
    rgba(8, 12, 16, 0.95)
  );

  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;

  will-change: transform;
  transition: transform 0.25s ease;
}

.hex-badge:hover {
  transform: translateY(-6px);
}

/* Inner Glowing Border */
.inner-border {
  position: absolute;
  inset: 6px;
  clip-path: inherit;
  border: 1px solid currentColor;
  opacity: 0.4;
  filter: blur(1px);
  pointer-events: none;
}

/* Variants */
.hex-badge.info { color: #3d8bff; }
.hex-badge.safe { color: #2a8f55; }
.hex-badge.warning { color: #f08a3c; }
.hex-badge.critical { color: #ff4d4d; }

/* Critical Glitch */
.glitch {
  animation: flicker 1.5s infinite;
}

@keyframes flicker {
  0% { opacity: 1; }
  5% { opacity: 0.6; }
  10% { opacity: 1; }
  15% { opacity: 0.7; }
  20% { opacity: 1; }
  100% { opacity: 1; }
}

/* Content */
.hex-content {
  text-align: center;
  z-index: 2;
}

.hex-label {
  display: block;
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 1px;
}

.hex-status {
  font-size: 11px;
  opacity: 0.7;
  letter-spacing: 1px;
}

.scan-line {
  position: absolute;
  top: -60%;
  left: 0;
  width: 100%;
  height: 60%;

  background: linear-gradient(
    to bottom,
    transparent,
    rgba(255,255,255,0.18),
    transparent
  );

  pointer-events: none;
  will-change: transform;
  animation: scan 2.8s linear infinite;
}


@keyframes scan {
  0% {
    transform: translateY(-120%);
  }
  100% {
    transform: translateY(220%);
  }
}

/* Rotating Tactical Ring */
.corner-rotor {
  position: absolute;
  width: 220%;
  height: 220%;
  border: 1px dashed currentColor;
  border-radius: 50%;
  opacity: 0.06;
  animation: rotate 14s linear infinite;
}

@keyframes rotate {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

/* Expandable Panel */
.hex-details {
  width: 220px;
  padding: 16px;
  border-radius: 12px;
  background: rgba(15, 20, 25, 0.95);
  border: 1px solid rgba(255,255,255,0.06);
  font-size: 12px;
  color: #cfd8e3;
  backdrop-filter: blur(12px);
  will-change: transform, opacity;
}
